    public static $statFacets = array(
       array('Type'=>'Terminal','Number_Of_Stats'=>1, 'Description'=>'Terminal Tapestries are the most simplified, most basic that the Tapestry can be. All Facets share the same Terminal Boon.','Facet_Distribution'=>'1 Stat of 24 Facets.'),
       array('Type'=>'Eclipse','Number_Of_Stats'=>2, 'Description'=>'Eclipse Tapestries are split in two, half the Facets have one Boon, the other half another. This creates two Stats such as "Yin" and "Yang",  "Light" and "Dark", or "Brains" and "Brawn" ','Facet_Distribution'=>'2 Stats of 12 Facets.'),
       array('Type'=>'Triptych','Number_Of_Stats'=>3, 'Description'=>'Triptych Tapestries separate Facets into 3 equal Stats, often "Mind", "Body" and "Spirit", or "Power", "Finesse" and "Resistance".','Facet_Distribution'=>'3 Stats of 8 Facets.'),
