       array('Type'=>'Wu','Number_Of_Stats'=>5, 'Description'=>'Wu Tapestries are built around five stats. Most often this is based on the chinese elements "Wood","Earth", "Fire", "Metal" and "Water". ','Facet_Distribution'=>'5 Stats, 4 of 5 Facets, and 1 of 4.'),
