       array('Type'=>'Wonderful','Number_Of_Stats'=>7, 'Description'=>'Wonderful Tapestries use seven Stats. Often this is just the traditional six with an extra Stat added for flavour. E.g. "Luck" ','Facet_Distribution'=>'7 Stats, 3 of 4 Facets and 4 of 3 Facets.'),
       array('Type'=>'Heroic','Number_Of_Stats'=>8, 'Description'=>'Heroic Tapestries use eight Stats, these are often described as "Strength", "Dexterity", "Constitution", "Body", "Intelligence", "Ego", "Presence", and "Comeliness". ','Facet_Distribution'=>'8 Stats of 3 Facets each.'),
       array('Type'=>'Shadowed','Number_Of_Stats'=>9, 'Description'=>'Shadowed Tapestries use nine Stats. These stats are often defined as 3 groups of 3 Stats, the Physical "Strength", "Dexterity", "Stamina", the Social "Presence/Charisma", "Manipulation", "Composure/Appearence", and the Mental "Intelligence", "Wits" and "Resolve/Perception" ','Facet_Distribution'=>'9 Stats, 6 of 3 Facets and 3 of 2 Facets.'),
